#!/usr/bin/env bash
set -euo pipefail
# Generated by Juanie schema management.
# Prefer Atlas for real migration generation instead of editing scaffold SQL by hand.
# Required env: ATLAS_DEV_URL and optional ATLAS_IMAGE
if [ -f bun.lockb ] || [ -f bun.lock ]; then
  bun install --frozen-lockfile
elif [ -f pnpm-lock.yaml ]; then
  pnpm install --frozen-lockfile
elif [ -f yarn.lock ]; then
  yarn install --immutable
elif [ -f package-lock.json ]; then
  npm ci
else
  npm install
fi
DRIZZLE_CONFIG="${DRIZZLE_CONFIG:-$(ls drizzle.config.ts drizzle.config.mjs drizzle.config.js drizzle.config.cjs 2>/dev/null | head -n 1)}"
if [ -z "$DRIZZLE_CONFIG" ]; then
  echo "Unable to locate drizzle config" >&2
  exit 1
fi
npx drizzle-kit export --config "$DRIZZLE_CONFIG" > ".juanie/schema-repair/b0cc6af6-0b6c-4ac8-a09f-95c9423b6137.schema.sql"
ATLAS_IMAGE="${ATLAS_IMAGE:-arigaio/atlas:latest}"
if command -v atlas >/dev/null 2>&1; then
  atlas migrate diff "repair_b0cc6af6" --env repair --config "file://.juanie/schema-repair/b0cc6af6-0b6c-4ac8-a09f-95c9423b6137.atlas.hcl"
else
  docker run --rm \
    -v "$PWD:/workspace" \
    -w /workspace \
    -e ATLAS_DEV_URL="${ATLAS_DEV_URL:-}" \
    "$ATLAS_IMAGE" migrate diff "repair_b0cc6af6" \
    --env repair \
    --config "file://.juanie/schema-repair/b0cc6af6-0b6c-4ac8-a09f-95c9423b6137.atlas.hcl"
fi